svg.script:
(function () {
  var KEY = "generic";
  function collect() {
    var svg = document.querySelector("svg") || document.documentElement;
    var rootM = null; try { rootM = svg.getScreenCTM(); } catch (e) { rootM = null; }
    var rects = document.querySelectorAll("[data-mux-comp]");
    var out = [];
    for (var i = 0; i < rects.length; i++) {
      var r = rects[i], bb;
      try { bb = r.getBBox(); } catch (e) { continue; }
      var cx = bb.x + bb.width / 2, cy = bb.y + bb.height / 2;
      var m = null; try { if (rootM) m = rootM.inverse().multiply(r.getScreenCTM()); } catch (e) { m = null; }
      if (m) { var x = m.a * cx + m.c * cy + m.e, y = m.b * cx + m.d * cy + m.f; cx = x; cy = y; }
      var id = r.getAttribute("data-id"); if (!id) continue;
      out.push({ id: id, x: cx, y: cy });
    }
    return { key: KEY, components: out };
  }
  function send() {
    try {
      if (window.parent && window.parent !== window) {
        window.parent.postMessage({ __muxSolutionLayout: true, payload: collect() }, "*");
      }
    } catch (e) {}
  }
  function boot() { send(); setTimeout(send, 120); setTimeout(send, 500); }
  if (document.readyState === "loading") { window.addEventListener("DOMContentLoaded", boot); } else { boot(); }
  window.addEventListener("load", send);
})();
